PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT(YEAR(?start) AS ?year) ?teammate ?teammateLabel WHERE {
  {
    SELECT(MIN(?s) AS ?start) WHERE {
      wd:Q192707 p:P54 ?mem .
      ?mem pq:P580 ?s .
    }
  }
  wd:Q192707 p:P54 ?mem .
  ?mem pq:P580 ?start ; pq:P582 ?end ; ps:P54 ?team .
  ?teammate p:P54 ?teammateMem .
  ?teammateMem ps:P54 ?team ; pq:P580 ?tStart ; pq:P582 ?tEnd .
  FILTER(?teammate != wd:Q192707)
  FILTER(?tStart <= ?end && ?tEnd >= ?start)
  OPTIONAL {
    ?teammate rdfs:label ?teammateLabel
    FILTER(LANG(?teammateLabel) = "en")
  }
}

